// sizeof returns the size in bytes, so you have to divide by the sizeof one element
inline constexpr int GAUSSIAN_X_FIXED_POINT_TABLE_SIZE = sizeof(GAUSSIAN_X_FIXED_POINT_TABLE) / sizeof(GAUSSIAN_X_FIXED_POINT_TABLE[0]);

inline constexpr int GAUSSIAN_X_FIXED_POINT_TABLE_SCALE = 10000;

inline int lookup_in_fixed_point_table(unsigned int random_num) {
    int index = (random_num % (GAUSSIAN_X_FIXED_POINT_TABLE_SIZE * 2)) - GAUSSIAN_X_FIXED_POINT_TABLE_SIZE;
    if (index < 0) {
        return -1 * (GAUSSIAN_X_FIXED_POINT_TABLE[(-1 * index) - 1]);
    }
    return GAUSSIAN_X_FIXED_POINT_TABLE[index];
}